+// ============================================================================
+// LoRA Adapter Support (Liquid Brain Architecture)
+// ============================================================================
+
+/// Type alias for LoRA adapter handle (uses C type directly)
+pub const AdapterLora = c.struct_llama_adapter_lora;
+
+/// Load a LoRA adapter from a GGUF file
+/// Returns a handle to the adapter that can be applied to contexts
+pub fn adapterLoraInit(
+    model: *const Model,
+    path_lora: [*:0]const u8,
+) !*AdapterLora {
+    const adapter = c.llama_adapter_lora_init(model.handle, path_lora);
+    if (adapter == null) return error.LoraLoadFailed;
+    return adapter.?;
+}
+
+/// Free a LoRA adapter and release its resources
+pub fn adapterLoraFree(adapter: *AdapterLora) void {
+    c.llama_adapter_lora_free(adapter);
+}
+
+/// Apply a LoRA adapter to a context with the specified scale factor
+/// scale: Adapter strength (0.0 = disabled, 1.0 = full, >1.0 = amplified)
+/// Multiple adapters can be applied simultaneously with different scales
+pub fn setAdapterLora(
+    ctx: *const Context,
+    adapter: *AdapterLora,
+    scale: f32,
+) !void {
+    const result = c.llama_set_adapter_lora(ctx.handle, adapter, scale);
+    if (result != 0) return error.AdapterSetFailed;
+}
+
+/// Remove a specific LoRA adapter from a context
+pub fn removeAdapterLora(
+    ctx: *const Context,
+    adapter: *AdapterLora,
+) !void {
+    const result = c.llama_rm_adapter_lora(ctx.handle, adapter);
+    if (result != 0) return error.AdapterRemoveFailed;
+}
+
+/// Clear all LoRA adapters from a context
+pub fn clearAdapterLora(ctx: *const Context) void {
+    c.llama_clear_adapter_lora(ctx.handle);
+}
+
+/// Get the number of metadata key-value pairs in an adapter
+pub fn adapterMetaCount(adapter: *const AdapterLora) i32 {
+    return c.llama_adapter_meta_count(adapter);
+}
+
+/// Get metadata value by key from an adapter
+/// Returns error if key not found
+pub fn adapterMetaValStr(
+    adapter: *const AdapterLora,
+    key: [*:0]const u8,
+    buf: []u8,
+) !usize {
+    const result = c.llama_adapter_meta_val_str(
+        adapter,
+        key,
+        buf.ptr,
+        @intCast(buf.len),
+    );
+    if (result < 0) return error.MetadataNotFound;
+    return @intCast(result);
+}
+
+/// Get metadata key by index
+pub fn adapterMetaKeyByIndex(
+    adapter: *const AdapterLora,
+    index: i32,
+    buf: []u8,
+) !usize {
+    const result = c.llama_adapter_meta_key_by_index(
+        adapter,
+        index,
+        buf.ptr,
+        @intCast(buf.len),
+    );
+    if (result < 0) return error.IndexOutOfBounds;
+    return @intCast(result);
+}
+
+/// Get metadata value by index
+pub fn adapterMetaValStrByIndex(
+    adapter: *const AdapterLora,
+    index: i32,
+    buf: []u8,
+) !usize {
+    const result = c.llama_adapter_meta_val_str_by_index(
