+const std = @import("std");
+const llama = @import("llama.zig");
+const logger = @import("logger.zig");
+
+/// Metadata and state for a loaded LoRA adapter
+pub const AdapterInfo = struct {
+    id: []const u8, // User-friendly identifier (e.g., "my_code_style")
+    path: []const u8, // Filesystem path to .lora file
+    adapter: *llama.AdapterLora, // llama.cpp adapter handle
+    size_bytes: usize, // File size for memory budget tracking
+    last_used: i64, // Unix timestamp for LRU eviction
+    usage_count: u32, // How many times this adapter has been applied
+    metadata: std.StringHashMap([]const u8), // GGUF metadata (alpha, etc.)
+
+    pub fn deinit(self: *AdapterInfo, allocator: std.mem.Allocator) void {
+        allocator.free(self.id);
+        allocator.free(self.path);
+        var it = self.metadata.iterator();
+        while (it.next()) |entry| {
+            allocator.free(entry.key_ptr.*);
+            allocator.free(entry.value_ptr.*);
+        }
+        self.metadata.deinit();
+    }
+};
+
+/// Pool manager for LoRA adapters with memory budget awareness
+pub const LoraPool = struct {
+    allocator: std.mem.Allocator,
+    model: *const llama.Model,
+    adapters: std.StringHashMap(AdapterInfo), // id -> AdapterInfo
+    max_loaded: usize = 8, // Maximum number of loaded adapters
+    total_memory_bytes: usize = 0, // Current memory usage
+    max_memory_bytes: usize, // Memory budget limit
+    mutex: std.Thread.Mutex = .{},
+
+    const Self = @This();
+
+    /// Initialize LoRA pool with memory budget in GB
+    pub fn init(
+        allocator: std.mem.Allocator,
+        model: *const llama.Model,
+        max_memory_gb: f32,
+    ) !Self {
+        return Self{
+            .allocator = allocator,
+            .model = model,
+            .adapters = std.StringHashMap(AdapterInfo).init(allocator),
+            .max_memory_bytes = @intFromFloat(max_memory_gb * 1024 * 1024 * 1024),
+        };
+    }
+
+    /// Clean up all loaded adapters
+    pub fn deinit(self: *Self) void {
+        var it = self.adapters.iterator();
+        while (it.next()) |entry| {
+            llama.adapterLoraFree(entry.value_ptr.adapter);
+            entry.value_ptr.deinit(self.allocator);
+        }
+        self.adapters.deinit();
+    }
+
+    /// Load a LoRA adapter from file with LRU eviction if needed
+    pub fn loadAdapter(self: *Self, id: []const u8, path: []const u8) !void {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        // Check if already loaded
+        if (self.adapters.contains(id)) {
+            logger.debug("LoRA adapter '{s}' already loaded", .{id});
+            return;
+        }
+
+        // Get adapter file size for budget tracking
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+        const stat = try file.stat();
+        const size_bytes = stat.size;
+
+        // Evict adapters if over budget
+        while (self.total_memory_bytes + size_bytes > self.max_memory_bytes) {
+            try self.evictLRU();
+        }
+
+        // Create null-terminated path for C API
+        const path_z = try self.allocator.dupeZ(u8, path);
+        defer self.allocator.free(path_z);
+
+        // Load adapter through llama.cpp
+        const adapter = try llama.adapterLoraInit(self.model, path_z);
+        errdefer llama.adapterLoraFree(adapter);
+
+        // Parse GGUF metadata
+        var metadata = std.StringHashMap([]const u8).init(self.allocator);
+        errdefer {
+            var it = metadata.iterator();
+            while (it.next()) |entry| {
+                self.allocator.free(entry.key_ptr.*);
+                self.allocator.free(entry.value_ptr.*);
+            }
+            metadata.deinit();
+        }
+
+        const meta_count = llama.adapterMetaCount(adapter);
+        var i: i32 = 0;
+        while (i < meta_count) : (i += 1) {
+            var key_buf: [256]u8 = undefined;
+            var val_buf: [1024]u8 = undefined;
+
+            const key_len = llama.adapterMetaKeyByIndex(adapter, i, &key_buf) catch continue;
+            const val_len = llama.adapterMetaValStrByIndex(adapter, i, &val_buf) catch continue;
+
+            const key = try self.allocator.dupe(u8, key_buf[0..key_len]);
+            errdefer self.allocator.free(key);
+            const val = try self.allocator.dupe(u8, val_buf[0..val_len]);
+            errdefer self.allocator.free(val);
+
+            try metadata.put(key, val);
+        }
+
+        // Store adapter info
+        const id_owned = try self.allocator.dupe(u8, id);
+        errdefer self.allocator.free(id_owned);
+
+        const path_owned = try self.allocator.dupe(u8, path);
+        errdefer self.allocator.free(path_owned);
+
+        try self.adapters.put(id_owned, AdapterInfo{
+            .id = id_owned,
+            .path = path_owned,
+            .adapter = adapter,
+            .size_bytes = size_bytes,
+            .last_used = std.time.timestamp(),
+            .usage_count = 0,
+            .metadata = metadata,
+        });
+
+        self.total_memory_bytes += size_bytes;
+        logger.info("Loaded LoRA adapter '{s}' ({d} MB)", .{ id, size_bytes / (1024 * 1024) });
+    }
+
+    /// Unload a specific adapter and free its resources
+    pub fn unloadAdapter(self: *Self, id: []const u8) !void {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        var info = self.adapters.fetchRemove(id) orelse return error.AdapterNotFound;
+
+        llama.adapterLoraFree(info.value.adapter);
+        self.total_memory_bytes -= info.value.size_bytes;
+        info.value.deinit(self.allocator);
+
+        logger.info("Unloaded LoRA adapter '{s}'", .{id});
+    }
+
+    /// Get adapter handle and mark as recently used
+    pub fn getAdapter(self: *Self, id: []const u8) ?*llama.AdapterLora {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        if (self.adapters.getPtr(id)) |info| {
+            info.last_used = std.time.timestamp();
+            info.usage_count += 1;
+            return info.adapter;
+        }
+        return null;
+    }
+
+    /// Evict the least recently used adapter
+    fn evictLRU(self: *Self) !void {
+        var oldest_id: ?[]const u8 = null;
+        var oldest_time: i64 = std.math.maxInt(i64);
+
+        var it = self.adapters.iterator();
+        while (it.next()) |entry| {
+            if (entry.value_ptr.last_used < oldest_time) {
+                oldest_time = entry.value_ptr.last_used;
+                oldest_id = entry.key_ptr.*;
+            }
+        }
+
+        if (oldest_id) |id| {
+            logger.warn("Evicting LoRA adapter '{s}' (LRU)", .{id});
+            // Create owned copy since unloadAdapter will free the key
+            const id_copy = try self.allocator.dupe(u8, id);
+            defer self.allocator.free(id_copy);
+            try self.unloadAdapter(id_copy);
+        } else {
+            return error.NoAdaptersToEvict;
+        }
+    }
+
+    /// List all loaded adapter IDs
+    pub fn listAdapters(self: *Self, allocator: std.mem.Allocator) ![][]const u8 {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        var list = std.ArrayList([]const u8).init(allocator);
+        errdefer list.deinit();
+
+        var it = self.adapters.iterator();
+        while (it.next()) |entry| {
+            const id_copy = try allocator.dupe(u8, entry.key_ptr.*);
+            try list.append(id_copy);
+        }
+
+        return try list.toOwnedSlice();
+    }
+
+    /// Get current memory usage and budget statistics
+    pub fn getStats(self: *Self) struct {
+        loaded_count: usize,
+        total_memory_mb: f32,
+        max_memory_mb: f32,
+        utilization: f32,
+    } {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        const total_mb = @as(f32, @floatFromInt(self.total_memory_bytes)) / (1024 * 1024);
+        const max_mb = @as(f32, @floatFromInt(self.max_memory_bytes)) / (1024 * 1024);
+
+        return .{
+            .loaded_count = self.adapters.count(),
+            .total_memory_mb = total_mb,
+            .max_memory_mb = max_mb,
+            .utilization = if (max_mb > 0) (total_mb / max_mb) else 0,
+        };
+    }
+};

